#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;
#include &lt;pthread.h&gt;
#include &lt;unistd.h&gt;

int job_count = 0;
pthread_mutex_t lock = PTHREAD_MUTEX_INITIALIZER;
pthread_cond_t cond = PTHREAD_COND_INITIALIZER;

void* worker_thread(void* arg) {
    while (1) {
        pthread_mutex_lock(&lock);

        // The Spurious Wakeup Defense Loop
        // We MUST use 'while', not 'if'. If the OS wakes us up randomly, 
        // we check job_count. If it's still 0, we immediately go back to sleep.
        while (job_count == 0) {
            printf("Worker sleeping. 0% CPU.\n");
            pthread_cond_wait(&cond, &lock);
        }

        // We have been awoken, AND we currently hold the lock!
        job_count--;
        printf("Worker processed a job. Remaining: %d\n", job_count);

        pthread_mutex_unlock(&lock);
        sleep(1); // Simulate hard work outside the lock
    }
    return NULL;
}

void* producer_thread(void* arg) {
    while (1) {
        sleep(3); // Wait a bit, then generate a burst of jobs

        pthread_mutex_lock(&lock);
        job_count += 3;
        printf("\nProducer created 3 jobs!\n");
        pthread_mutex_unlock(&lock);

        // Wake up exactly 3 sleeping workers to handle the burst
        pthread_cond_signal(&cond);
        pthread_cond_signal(&cond);
        pthread_cond_signal(&cond);
    }
    return NULL;
}

pthread_mutex_t lock_A = PTHREAD_MUTEX_INITIALIZER;
pthread_mutex_t lock_B = PTHREAD_MUTEX_INITIALIZER;

void* thread_1_logic() {
    pthread_mutex_lock(&lock_A);
    sleep(1); // Simulate work
    pthread_mutex_lock(&lock_B); // Wants B

    // ... execute logic ...

    pthread_mutex_unlock(&lock_B);
    pthread_mutex_unlock(&lock_A);
}

void* thread_2_logic() {
    pthread_mutex_lock(&lock_B);
    sleep(1); // Simulate work
    pthread_mutex_lock(&lock_A); // Wants A

    // ... execute logic ...

    pthread_mutex_unlock(&lock_A);
    pthread_mutex_unlock(&lock_B);
}
